import type { NordicI18nMiddlewareConfig } from './middlewares';

export type NordicI18nConfig = NordicI18nMiddlewareConfig & {
  /**
   * Name of the repository on GitHub.
   *
   * For more info refer to the [docs](https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-i18n#configuration).
   *
   * @example 'fury_fbm-panel-frontend'
   */
  app: string;

  /**
   * Tag name to recognize the project inside Crowdin. **Avoid using rare characters**.
   *
   * For more info refer to the [docs](https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-i18n#configuration).
   *
   * @example 'fbmfulfillment'
   */
  project?: string;

  /**
   * Name of translation project in Crowdin.
   *
   * Actual apps that are already using the Babel service have a `translationProject: 'meli'` by default, so they don't need to specify this property.
   * **For new apps ask a CM team for the name**.
   *
   * For more info refer to the [docs](https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-i18n#configuration).
   *
   * @example 'fbm'
   */
  translationProject?: string;

  /**
   * File extensions that will be used to scan the terms.
   *
   * For more info refer to the [docs](https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-i18n#configuration).
   *
   * @default ['js']
   * @example ['js', 'jsx', 'ts', 'tsx']
   */
  extNames?: Array<string>;
};

declare global {
  namespace Nordic {
    interface Config {
      /**
       * i18n CLI config.
       *
       * For more info refer to the [docs](https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-i18n#cli).
       */
      i18n?: NordicI18nConfig;
    }
  }
}

type IsEqual<A, B> =
  (<G>() => G extends G | (A & G) ? 1 : 2) extends <G>() => G extends
    | G
    | (B & G)
    ? 1
    : 2
    ? true
    : false;

type Filter<KeyType, ExcludeType> =
  IsEqual<KeyType, ExcludeType> extends true
    ? never
    : KeyType extends ExcludeType
      ? never
      : KeyType;

/**
 * Based on type-fest's `Except` type.
 * [Link to implementation](https://github.com/sindresorhus/type-fest/blob/main/source/except.d.ts)
 */
export type Except<ObjectType, KeysType extends keyof ObjectType> = {
  [KeyType in keyof ObjectType as Filter<
    KeyType,
    KeysType
  >]: ObjectType[KeyType];
};

// eslint-disable-next-line @typescript-eslint/consistent-indexed-object-style
type Without<FirstType, SecondType> = {
  [KeyType in Exclude<keyof FirstType, keyof SecondType>]?: never;
};

/**
 * Based on type-fest's `MergeExclusive` type.
 * [Link to implementation](https://github.com/sindresorhus/type-fest/blob/main/source/merge-exclusive.d.ts)
 */
export type MergeExclusive<FirstType, SecondType> =
  | FirstType
  | SecondType extends object
  ?
      | (FirstType & Without<SecondType, FirstType>)
      | (SecondType & Without<FirstType, SecondType>)
  : FirstType | SecondType;
